import chalk from 'chalk';
import { createSqliteStorage } from '@flusk/resources';
import { primitives } from '@flusk/business-logic';

// --- BEGIN CUSTOM ---
const SLM_INPUT_COST = 0.0001;
const SLM_OUTPUT_COST = 0.0002;

export function trainingSavingsAction(): void {
  const storage = createSqliteStorage();
  const clusters = storage.trainingPairs.countByClusterGrouped() as Array<{
    cluster: string; count: number;
  }>;

  if (clusters.length === 0) {
    console.log(chalk.dim('No clusters to estimate savings for.'));
    return;
  }

  console.log(chalk.bold('\n💰 Estimated Savings per Cluster\n'));
  const header = [
    pad('Cluster', 25), pad('Pairs', 8),
    pad('Teacher $', 12), pad('SLM $', 12), pad('Savings', 12),
  ].join('  ');
  console.log(chalk.bold(header));
  console.log(chalk.dim('─'.repeat(70)));

  for (const c of clusters) {
    const result = primitives.estimateSavings(
      c.count, 500, 200,
      0.005, 0.015,
      SLM_INPUT_COST, SLM_OUTPUT_COST,
    ) as { teacherCost: number; slmCost: number; savings: number; savingsPercent: number };

    const row = [
      pad(c.cluster, 25),
      pad(String(c.count), 8),
      pad(`$${result.teacherCost.toFixed(2)}`, 12),
      pad(`$${result.slmCost.toFixed(2)}`, 12),
      pad(`${result.savingsPercent.toFixed(0)}%`, 12),
    ].join('  ');
    console.log(row);
  }
  console.log();
}

function pad(s: string, len: number): string {
  return s.length >= len ? s.slice(0, len) : s + ' '.repeat(len - s.length);
}
